INSERT OR IGNORE INTO companies (id, name, type, website, description, priority, industry_segment, estimated_gpu_scale, financing_status, qualification_score, created_at, updated_at, founded_year, employee_count, total_raised, last_funding_round, investors, headquarters, linkedin_url, twitter_url, github_url, recent_news, hiring_signals, last_enriched_at, sec_ticker, sec_cik, gpu_asset_value, depreciation_schedule, open_roles_count, key_hires, nvidia_partnership, outreach_status, manual_call_made, phone, talking_points, call_notes) VALUES ('b58f75e0-5a7b-4775-8306-42b3c6702e27', 'Voltage Park', 'operator', 'https://voltagepark.com', 'Cloud AI infrastructure company with $1bn backing and 100+ customers. One of the largest independent GPU cloud operators in the US.', 'C', 'AI Cloud', '24,000 NVIDIA H100 GPUs (~$1B worth), fully paid, zero debt, zero leasing. Expanded to 35,000+ H100/B200/GB300 post Lightning AI merger (Jan 2026). Six Tier 3 data centers in TX, VA, WA.', 'No debt or leasing — fully equity-funded via Jed McCaleb / Navigation Fund. Merged with Lightning AI in January 2026.', '58', '2026-03-21 02:26:32', '2026-03-25 14:29:22', NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.linkedin.com/company/voltage-park', 'https://x.com/VoltagePark', NULL, '[{"title":"Accessible AI Compute. Exceptional Customer Service."},{"title":"Lightning AI and Voltage Park Complete Merger to Create the First Cloud Built for AI"}]', 'actively hiring', '2026-03-24 18:44:35', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'uncontacted', '0', '+13986636971', '{"points":["I saw Voltage Park is running 24,000 NVIDIA H100 GPUs (~$1B worth), fully paid, zero debt, zero leasing. Expanded to 35,000+ H100/B200/GB300 post Lightning AI merger (Jan 2026). Six Tier 3 data centers in TX, VA, WA. — at that scale, the financing structure on hardware really starts to matter.","If you''re looking at debt financing for your next deployment, lenders will ask about residual value on the hardware. We can make that conversation much easier.","The practical effect is you can get better terms — whether that''s lower cost of capital, higher advance rates, or longer tenor on the debt.","I also saw the recent news about Accessible AI Compute. Exceptional Customer Service. — that''s actually what prompted me to reach out, since residual value coverage becomes more relevant as you scale.","Cloud providers especially benefit because the utilization model means GPUs cycle through faster — having residual value coverage from day one protects the financing.","I''m not trying to sell anything on this call — I just want to see if it''s worth 20 minutes with my co-founders Isaac and Josh to walk through how it works.","If it helps, we''re not asking you to change your financing structure. We slot into whatever you already have or are building."],"followups":["Do you already have a lender asking about collateral value at maturity for your upcoming deployments?","Are you financing owned GPUs, leased, or both?"],"generated_at":"2026-03-25T14:29:22.580Z"}', '');
