INSERT OR IGNORE INTO companies (id, name, type, website, description, priority, industry_segment, estimated_gpu_scale, financing_status, qualification_score, created_at, updated_at, founded_year, employee_count, total_raised, last_funding_round, investors, headquarters, linkedin_url, twitter_url, github_url, recent_news, hiring_signals, last_enriched_at, sec_ticker, sec_cik, gpu_asset_value, depreciation_schedule, open_roles_count, key_hires, nvidia_partnership, outreach_status, manual_call_made, phone, talking_points, call_notes) VALUES ('4452c965-c887-40f0-9068-50ddd772569c', 'RunPod', 'operator', 'https://runpod.io', 'GPU cloud marketplace offering serverless and dedicated GPU instances for AI training and inference. Grew to 400K+ developers and $120M ARR by late 2025.', 'C', 'AI Cloud', '10,000+ GPUs (distributed)', 'Seed 2024', '78', '2026-03-21 13:30:25', '2026-03-25 14:29:22', NULL, NULL, '$20M', NULL, NULL, 'Moorestown, NJ, USA', 'https://www.linkedin.com/company/runpod-io/', 'https://x.com/runpod', 'https://github.com/runpod', 'Runpod Blog. | The AI market looks nothing like the narrative | LLM inference optimization: techniques that actually reduce latency and cost | Introducing Flash: Run GPU workloads on Runpod Serverless: No Docker required | Pruna P-Video and Vidu Q3 public endpoints now available on Runpod', NULL, '2026-03-25T16:44:02.451Z', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'uncontacted', '0', '(703) 276-0100', '{"points":["I saw RunPod is running 10,000+ GPUs (distributed) — at that scale, the financing structure on hardware really starts to matter.","Given your active financing — I saw the $20M raise, one thing lenders typically get stuck on is what the GPUs will be worth at maturity. That''s exactly what we solve.","The practical effect is you can get better terms — whether that''s lower cost of capital, higher advance rates, or longer tenor on the debt.","Cloud providers especially benefit because the utilization model means GPUs cycle through faster — having residual value coverage from day one protects the financing.","I''m not trying to sell anything on this call — I just want to see if it''s worth 20 minutes with my co-founders Isaac and Josh to walk through how it works.","If it helps, we''re not asking you to change your financing structure. We slot into whatever you already have or are building."],"followups":["Do you already have a lender asking about collateral value at maturity for your upcoming deployments?","Are you financing owned GPUs, leased, or both?"],"generated_at":"2026-03-25T14:29:22.576Z"}', '');
