INSERT OR IGNORE INTO companies (id, name, type, website, description, priority, industry_segment, estimated_gpu_scale, financing_status, qualification_score, created_at, updated_at, founded_year, employee_count, total_raised, last_funding_round, investors, headquarters, linkedin_url, twitter_url, github_url, recent_news, hiring_signals, last_enriched_at, sec_ticker, sec_cik, gpu_asset_value, depreciation_schedule, open_roles_count, key_hires, nvidia_partnership, outreach_status, manual_call_made, phone, talking_points, call_notes) VALUES ('42143b14-a85b-437e-a089-42e9d7397b1a', 'Runway Growth Capital (formerly known as Western Technology)', 'lender', 'https://runwaygrowth.com', 'Growth-stage venture lender (formerly Western Technology Investment spinout) providing non-dilutive capital to technology companies. Expanding AI/GPU infrastructure book with venture debt.', 'A', 'Private Credit', 'N/A', 'Active lender', '76', '2026-03-21 13:30:25', '2026-03-25 14:29:22', NULL, NULL, '$1.5B+ AUM', NULL, NULL, 'Menlo Park, CA, USA', 'https://www.linkedin.com/company/runway-growth-capital/', 'https://x.com/RunwayGrowth', NULL, NULL, NULL, '2026-03-25T16:36:09.966Z', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'uncontacted', '0', '9690063810', '{"points":["I''ve been looking at Runway Growth Capital (formerly known as Western Technology)''s work in Growth-stage venture lender (formerly Western Technology Investment spinout) providing non-dilutive capital to techno.... We''re building something that could expand the deals you can do in GPU-backed lending.","The GPU lending space is growing fast, but most lenders get stuck on one question: what''s the hardware worth at maturity? We provide a definitive answer.","We provide residual value coverage that gives you a floor on the collateral. That means you can underwrite more aggressively — better advance rates, longer tenor, more deal flow.","Given your scale, even a small improvement in how you underwrite GPU collateral could open up a meaningful pipeline of new deals.","We''re not adding complexity to the deal — this is designed to make your existing credit process work better for hardware-backed lending.","Would it be worth a 20-minute call with our founders to walk through a couple of real deal structures where this has made a difference?"],"followups":["What''s the typical tenor you''re comfortable with on hardware-backed facilities?","Is the bigger constraint on your side advance rate, or residual value assumptions?"],"generated_at":"2026-03-25T14:29:22.577Z"}', '');
