INSERT OR IGNORE INTO companies (id, name, type, website, description, priority, industry_segment, estimated_gpu_scale, financing_status, qualification_score, created_at, updated_at, founded_year, employee_count, total_raised, last_funding_round, investors, headquarters, linkedin_url, twitter_url, github_url, recent_news, hiring_signals, last_enriched_at, sec_ticker, sec_cik, gpu_asset_value, depreciation_schedule, open_roles_count, key_hires, nvidia_partnership, outreach_status, manual_call_made, phone, talking_points, call_notes) VALUES ('d4d41889-2ac7-4d0f-bf53-2b35086deda6', 'CoreWeave', 'operator', 'coreweave.com', 'GPU-native cloud provider, publicly traded post-March 2025 IPO. Among the largest independent GPU fleets globally with 100K+ H100s. Runs massive GPU-backed debt facilities.', 'C', 'GPU Cloud / AI Infrastructure', '100,000+ H100/H200 GPUs', '$25B+ raised via equity and debt (GPU-backed)', '55', '2026-03-21 17:20:50', '2026-03-25 14:29:22', NULL, NULL, '$25B+', NULL, NULL, 'Roseland, NJ', 'https://www.linkedin.com/company/coreweave', 'https://x.com/CoreWeave', NULL, 'Engineered for Agentic AI: NVIDIA HGX B300 on CoreWeave Cloud | Why AI pioneers like Cursor and Decart AI partner with CoreWeave for NVIDIA HGX B300 | Accelerated pace that drives breakthroughs | Engineered for performance | Performance in practice', NULL, '2026-03-25T16:44:02.451Z', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'uncontacted', '0', '(703) 276-0100', '{"points":["I saw CoreWeave is running 100,000+ H100/H200 GPUs — at that scale, the financing structure on hardware really starts to matter.","Given your active financing — I saw the $25B+ raise, one thing lenders typically get stuck on is what the GPUs will be worth at maturity. That''s exactly what we solve.","The practical effect is you can get better terms — whether that''s lower cost of capital, higher advance rates, or longer tenor on the debt.","Cloud providers especially benefit because the utilization model means GPUs cycle through faster — having residual value coverage from day one protects the financing.","I''m not trying to sell anything on this call — I just want to see if it''s worth 20 minutes with my co-founders Isaac and Josh to walk through how it works.","If it helps, we''re not asking you to change your financing structure. We slot into whatever you already have or are building."],"followups":["Do you already have a lender asking about collateral value at maturity for your upcoming deployments?","Are you financing owned GPUs, leased, or both?"],"generated_at":"2026-03-25T14:29:22.584Z"}', '');
