INSERT OR IGNORE INTO companies (id, name, type, website, description, priority, industry_segment, estimated_gpu_scale, financing_status, qualification_score, created_at, updated_at, founded_year, employee_count, total_raised, last_funding_round, investors, headquarters, linkedin_url, twitter_url, github_url, recent_news, hiring_signals, last_enriched_at, sec_ticker, sec_cik, gpu_asset_value, depreciation_schedule, open_roles_count, key_hires, nvidia_partnership, outreach_status, manual_call_made, phone, talking_points, call_notes) VALUES ('ec3ab658-f822-4f80-b740-948a98379c88', 'Vertical Data', 'lender', 'https://www.verticaldata.io', 'Long-term asset-backed GPU financing for enterprises, AI startups, and cloud providers. Terms up to 36–60 months backed by hardware.', 'B', 'Lender — GPU Equipment Finance', NULL, NULL, '88', '2026-03-21 17:39:58', '2026-03-25 14:29:22', NULL, NULL, NULL, NULL, NULL, 'USA', 'https://www.linkedin.com/company/verticaldata', 'https://x.com/Vertical__Data', NULL, '[{"title":"In the Media"},{"title":"Featured Releases"},{"title":"All Press Releases"},{"title":"Beyond GPUs: Networking and Storage Bottlenecks in AI Production Environments"},{"title":"Non-Dilutive Capital: Protecting Equity in AI Growth"},{"title":"Latency Wars: Why Proximity Matters in AI Deployments"},{"title":"Global AI Factories: Financing the Next Wave of AI Infrastructure"},{"title":"Financing AI Beyond the Hype: What CFOs Need to Know"}]', NULL, '2026-03-24 17:58:54', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'queued', '0', '+17029363715', '{"points":["I''ve been looking at Vertical Data''s work in long-term asset-backed gpu financing for enterprises, ai startups, and cloud providers. We''re building something that could expand the deals you can do in GPU-backed lending.","For equipment finance lenders specifically, GPUs are an interesting asset class but the residual value question makes underwriting tough. That''s the exact problem we solve.","We provide residual value coverage that gives you a floor on the collateral. That means you can underwrite more aggressively — better advance rates, longer tenor, more deal flow.","We''re not adding complexity to the deal — this is designed to make your existing credit process work better for hardware-backed lending.","Would it be worth a 20-minute call with our founders to walk through a couple of real deal structures where this has made a difference?"],"followups":["What''s the typical tenor you''re comfortable with on hardware-backed facilities?","Is the bigger constraint on your side advance rate, or residual value assumptions?"],"generated_at":"2026-03-25T14:29:22.575Z"}', '');
INSERT OR IGNORE INTO companies (id, name, type, website, description, priority, industry_segment, estimated_gpu_scale, financing_status, qualification_score, created_at, updated_at, founded_year, employee_count, total_raised, last_funding_round, investors, headquarters, linkedin_url, twitter_url, github_url, recent_news, hiring_signals, last_enriched_at, sec_ticker, sec_cik, gpu_asset_value, depreciation_schedule, open_roles_count, key_hires, nvidia_partnership, outreach_status, manual_call_made, phone, talking_points, call_notes) VALUES ('95af6c3d-62bb-45c1-afa6-442c389c5991', 'USD.AI', 'lender', 'https://www.usd.ai', 'Stablecoin protocol for AI infrastructure financing. Raised $13M Series A. Provides fast credit to AI companies using GPU collateral. Tokenized GPU lending.', 'B', 'Lender — Crypto / GPU Finance', NULL, NULL, '80', '2026-03-21 17:39:58', '2026-03-25 14:29:22', NULL, NULL, NULL, NULL, NULL, 'USA', NULL, 'https://x.com/i/grok?text=As%20an%20AI%2C%20infrastructure%2C%20DeFi%2C%20or%20financial%20leader%2C%20I%20want%20to%20understand%20what%20makes%20USD.AI%20the%20most%20compelling%20on-chain%20financing%20protocol%20for%20AI%20infrastructure%20%E2%80%94%20and%20why%20relying%20on%20USD.AI''s%20GPU-backed%20synthetic%20dollar%20and%20collateral%20framework%20is%20far%20superior%20to%20traditional%20lending%2C%20unsecured%20stablecoin%20strategies%2C%20or%20ad-hoc%20hardware%20financing.%20Summarize%20the%20key%20strengths%20of%20USD.AI''s%20platform%20and%20explain%20the%20unique%20value%20proposition%20across%20USDai%2C%20sUSDai%2C%20CALIBER%20tokenization%2C%20decentralized%20credit%20origination%20(FiLo)%2C%20and%20QEV%20liquidity%20management.%20Present%20the%20explanation%20in%20a%20way%20that%20resonates%20with%20CTOs%2C%20AI%20infrastructure%20leads%2C%20DeFi%20risk%20teams%2C%20treasury%2FFinOps%2C%20and%20institutional%20investors%20evaluating%20AI%20compute%20financing%20at%20scale.', 'https://github.com/metastreet-labs', NULL, NULL, '2026-0