INSERT OR IGNORE INTO companies (id, name, type, website, description, priority, industry_segment, estimated_gpu_scale, financing_status, qualification_score, created_at, updated_at, founded_year, employee_count, total_raised, last_funding_round, investors, headquarters, linkedin_url, twitter_url, github_url, recent_news, hiring_signals, last_enriched_at, sec_ticker, sec_cik, gpu_asset_value, depreciation_schedule, open_roles_count, key_hires, nvidia_partnership, outreach_status, manual_call_made, phone, talking_points, call_notes) VALUES ('667bf1dc-0d7f-4837-a520-748d65aebede', 'Inteleca', 'operator', 'https://www.inteleca.com', 'IT asset disposition and AI hardware refresh specialist. Focuses on enterprise GPU refresh cycles and secondary market placement.', 'C', 'Adjacent — ITAD / GPU', NULL, NULL, '72', '2026-03-21 17:39:58', '2026-03-25 14:29:22', NULL, NULL, NULL, NULL, NULL, 'USA', 'https://www.linkedin.com/company/inteleca-it-business-solutions', 'https://twitter.com/IntelecaIT', NULL, NULL, NULL, '2026-03-25T16:39:30.198Z', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'uncontacted', '0', '800-961-3094', '{"points":["I''ve been looking into Inteleca — it asset disposition and ai hardware refresh specialist. We work with companies in this space on the financing side.","When operators go to finance GPU clusters, lenders always ask: what''s the hardware worth in 3-4 years? We give them an answer they can underwrite against.","The practical effect is you can get better terms — whether that''s lower cost of capital, higher advance rates, or longer tenor on the debt.","I''m not trying to sell anything on this call — I just want to see if it''s worth 20 minutes with my co-founders Isaac and Josh to walk through how it works.","If it helps, we''re not asking you to change your financing structure. We slot into whatever you already have or are building."],"followups":["Do you already have a lender asking about collateral value at maturity for your upcoming deployments?","Are you financing owned GPUs, leased, or both?"],"generated_at":"2026-03-25T14:29:22.578Z"}', '');
