INSERT OR IGNORE INTO research_notes (id, company_id, source_url, summary, raw_data, created_at) VALUES ('066a2451-29e6-47fa-ba05-bd050726f546', 'eeab4f25-1dbf-465c-a512-5c9618546fda', 'https://hyperbolic.xyz', 'Weak-to-moderate fit — Hyperbolic is a marketplace/aggregator, not an owned-GPU operator. They don''t hold hardware assets so residual value coverage is less directly applicable. However, if they''re facilitating large GPU transactions, there may be a play. Small $20M total raise — early stage. CEO Jasper Zhang is primary contact.

