INSERT OR IGNORE INTO research_notes (id, company_id, source_url, summary, raw_data, created_at) VALUES ('831c89dc-faa5-45f4-94c9-0fcf3e4c029b', '1267a741-f052-45a2-96f6-1e6222e1c8ba', 'https://phoenixnap.com', 'Uncertain — in the middle of M&A/restructuring activity. Goldman sale process and asset divestiture make this a complicated target right now. GPU scale is real but management attention is on M&A. Could be a good post-acquisition conversation if buyer is identified.

