INSERT OR IGNORE INTO research_notes (id, company_id, source_url, summary, raw_data, created_at) VALUES ('38087df7-ae26-4c95-a62f-9b6edf3f1222', '86f60581-89d9-499e-8f40-de5c80af164b', 'https://kingstreet.com', 'INVESTOR/PARTNER — King Street already owns Colovore (a GPU colocation operator). Brian Higgins personally endorsed Colovore CEO appointment. The Crusoe GPU credit facility also listed King Street as syndication partner. Very relevant to Corgi''s proposition — they clearly understand GPU collateral value. Approach as sophisticated co-investor.

