INSERT OR IGNORE INTO enrichment_log (id, entity_type, entity_id, source, data_found, created_at) VALUES ('ed458475-dac2-414b-a4e5-15973c96a84a', 'company', '5dc51984-00b9-4bd6-8491-6584f93591ec', 'company-website', '{"source":"company-website","entityType":"company","entityId":"5dc51984-00b9-4bd6-8491-6584f93591ec","data":{"socialLinks":{"twitter":"https://twitter.com/garrrikkotua/status/1786042460143247506","linkedin":"https://www.linkedin.com/company/modal-labs/","github":"https://github.com/modal-labs","youtube":"https://www.youtube.com/channel/UC477UdoLR2Js3RHhRWSXsQA"},"emails":[],"phones":[],"description":"From training to inference: Scaling RL systems on Modal Register Product Solutions Resources CustomersPricingDocs Log In Sign Up Making cloud developmentwork like magic We''re hiring! Our founders Erik Bernhardsson and Akshat Bubna, pictured with Mugi (Akshat''s dog). Not pictured: Erik''s cats Lance and Stan. We started Modal with the goal to make it easier to iterate and ship applications for data, AI, and machine learning. In order to deliver the developer experience we wanted, we went deep and built our own infrastructure — including our own custom file system, container runtime, scheduler, container image builder, and much more.Customers use Modal for a wide range of use cases, including Generative AI inference, LLM fine-tuning, computational biotech, and media processing. We''re focused ","newsItems":["How Quora uses Modal to run thousands of Python sandboxes simultaneously","A code interpreter for Poe","A Modal Function by any other name","Build fast like Quora","Ship your first app in minutes."],"hiringSignals":{"isHiring":false,"openRoles":null,"departments":[],"signal":"not clearly hiring"},"linkedin_url":"https://www.linkedin.com/company/modal-labs/","twitter_url":"https://twitter.com/garrrikkotua/status/1786042460143247506","github_url":"https://github.com/modal-labs","recent_news":"[{\"title\":\"How Quora uses Modal to run thousands of Python sandboxes simultaneously\"},{\"title\":\"A code interpreter for Poe\"},{\"title\":\"A Modal Function by any other name\"},{\"title\":\"Build fast like Quora\"},{\"title\":\"Ship your first app in minutes.\"}]","hiring_signals":"not clearly hiring"},"enrichedAt":"2026-03-24T18:25:53.343Z","success":true}', '2026-03-24 18:26:57');
