INSERT OR IGNORE INTO enrichment_log (id, entity_type, entity_id, source, data_found, created_at) VALUES ('6a0c887f-befe-47e9-b930-6ce5fe1d2677', 'company', '0e3d657f-50b5-4384-8aa4-871bab44a5fa', 'company-website', '{"source":"company-website","entityType":"company","entityId":"0e3d657f-50b5-4384-8aa4-871bab44a5fa","data":{"socialLinks":{"twitter":"https://x.com/replicate","github":"https://github.com/replicate"},"emails":[],"phones":["4923224863","840701-0041","1898188199"],"description":"Replicate has joined CloudflareReplicate glyphExplorePricingEnterpriseDocsBlogSign inTry for freeMenuExplorePricingEnterpriseDocsBlogSign inTry for freeCompare models in the PlaygroundThis goo was created with a model on Replicate: andreasjansson/plasmaWe''re bringing AI to every software developer.AI can do extraordinary things, but it''s still too hard to use.We don''t believe AI is inherently hard. We just don''t have the right tools and abstractions yet.We''re building tools so all software engineers can use AI as if it were normal software. You should be able to import an image generator the same way you import an npm package. You should be able to customize a model as easily as you can fork something on GitHub.Read more about what we''re doing and why on our blog.Our investorsAdam WigginsF","newsItems":["Replicate is joining Cloudflare"],"twitter_url":"https://x.com/replicate","github_url":"https://github.com/replicate","recent_news":"[{\"title\":\"Replicate is joining Cloudflare\"}]"},"enrichedAt":"2026-03-24T18:26:59.376Z","success":true}', '2026-03-24 18:28:03');
